script:
frappe.ui.form.on("Student ID Card", {
    student: function(frm) {

        if (!frm.doc.student) {
            return;
        }

        frappe.db.get_doc("Custom Student", frm.doc.student).then(function(student) {

            frm.set_value("student_name", student.student_name);
            frm.set_value("academic_year", student.current_academic_year);
            frm.set_value("program", student.current_program);
            frm.set_value("roll_no", student.roll_no);
            frm.set_value("blood_group", student.blood_group);
            frm.set_value("mobile", student.student_mobile_number);
            frm.set_value("photo", student.image);

        });

    }
});
